import { useEffect, useState } from "react";
import axiosInstance from "../axiosConfig";

const AdminDashboard = () => {
  const [plans, setPlans] = useState([]);
  const [form, setForm] = useState({
    name: "",
    price: "",
    duration: "monthly",
    features: "",
  });

  const fetchPlans = async () => {
    try {
      const res = await axiosInstance.get("/api/plans");
      setPlans(res.data);
    } catch (error) {
      console.error("ADMIN FETCH PLANS ERROR:", error);
      alert("Failed to load plans");
    }
  };

  const handleCreate = async () => {
    if (!form.name || !form.price) {
      return alert("Name and price are required");
    }

    try {
      await axiosInstance.post("/api/plans", {
        name: form.name,
        price: Number(form.price),
        duration: form.duration,
        features: form.features
          ? form.features.split(",").map((f) => f.trim())
          : [],
      });

      setForm({
        name: "",
        price: "",
        duration: "monthly",
        features: "",
      });

      fetchPlans();
    } catch (error) {
      console.error(
        "ADMIN CREATE PLAN ERROR:",
        error.response?.data || error.message
      );
      alert("Failed to create plan");
    }
  };

  const handleDelete = async (id) => {
    try {
      await axiosInstance.delete(`/api/plans/${id}`);
      fetchPlans();
    } catch (error) {
      console.error(
        "ADMIN DELETE PLAN ERROR:",
        error.response?.data || error.message
      );
      alert("Failed to delete plan");
    }
  };

  useEffect(() => {
    fetchPlans();
  }, []);

  return (
    <div style={{ maxWidth: "900px", margin: "40px auto", padding: "0 20px" }}>
      
      {/* HEADER */}
      <div style={{ textAlign: "center", marginBottom: "30px" }}>
        <h1 style={{ fontSize: "26px", marginBottom: "6px" }}>
          Admin Dashboard
        </h1>
        <p style={{ color: "#6b7280", fontSize: "14px" }}>
          Manage subscription plans and pricing
        </p>
      </div>

      {/* CREATE PLAN */}
      <div className="card" style={{ marginBottom: "30px" }}>
        <h2 style={{ marginBottom: "16px", textAlign: "center" }}>
          Create Plan
        </h2>

        <input
          type="text"
          placeholder="Plan name"
          value={form.name}
          onChange={(e) =>
            setForm({ ...form, name: e.target.value })
          }
        />

        <input
          type="number"
          placeholder="Price (AUD)"
          value={form.price}
          onChange={(e) =>
            setForm({ ...form, price: e.target.value })
          }
        />

        <select
          value={form.duration}
          onChange={(e) =>
            setForm({ ...form, duration: e.target.value })
          }
        >
          <option value="monthly">Monthly</option>
          <option value="yearly">Yearly</option>
        </select>

        <input
          type="text"
          placeholder="Features (comma separated)"
          value={form.features}
          onChange={(e) =>
            setForm({ ...form, features: e.target.value })
          }
        />

        <button
          onClick={handleCreate}
          className="btn-primary"
          style={{ width: "100%", marginTop: "10px" }}
        >
          Create Plan
        </button>
      </div>

      {/* PLANS LIST */}
      <div>
        <h2 style={{ textAlign: "center", marginBottom: "20px" }}>
          Existing Plans
        </h2>

        {plans.length === 0 && (
          <p style={{ color: "#777", textAlign: "center" }}>
            No plans available
          </p>
        )}

        {plans.map((plan) => (
          <div
            key={plan._id}
            className="card"
            style={{ maxWidth: "600px", margin: "0 auto 16px" }}
          >
            <div
              style={{
                display: "flex",
                justifyContent: "space-between",
                alignItems: "center",
              }}
            >
              <div>
                <h3>{plan.name}</h3>
                <p style={{ color: "#555", fontSize: "14px" }}>
                  ${plan.price} • {plan.duration}
                </p>
              </div>

              <button
                onClick={() => handleDelete(plan._id)}
                className="btn-danger"
              >
                Delete
              </button>
            </div>

            {plan.features?.length > 0 && (
              <ul style={{ marginTop: "10px", paddingLeft: "18px" }}>
                {plan.features.map((feature, index) => (
                  <li key={index} style={{ color: "#666", fontSize: "14px" }}>
                    {feature}
                  </li>
                ))}
              </ul>
            )}
          </div>
        ))}
      </div>
    </div>
  );
};

export default AdminDashboard;
